SELECT COUNT(*)
FROM tbl_chat_room
WHERE room_id = #{roomId}
  AND room_status = 1
  AND (
        fk_jobseeker_memberid = #{memberId}
     OR fk_company_memberid   = #{memberId}
  )

SELECT COUNT(*)
FROM tbl_chat_message CM
JOIN tbl_chat_room R
  ON CM.fk_room_id = R.room_id
WHERE R.room_status = 1
  AND CM.deleted_yn = 0
  AND CM.sender_memberid != #{memberId}
  AND (
        R.fk_jobseeker_memberid = #{memberId}
     OR R.fk_company_memberid   = #{memberId}
  )
  AND CM.message_id >
      NVL(
          (
              SELECT CR.last_read_message_id
              FROM tbl_chat_read CR
              WHERE CR.fk_room_id = CM.fk_room_id
                AND CR.fk_memberid = #{memberId}
          ),
          0
      )

SELECT *
FROM (
    SELECT
        CM.message_id      AS messageId,
        CM.fk_room_id      AS roomId,
        CM.sender_memberid AS senderMemberId,
        CM.content         AS content,
        TO_CHAR(CM.created_at, 'YYYY.MM.DD HH24:MI:SS') AS createdAt,

        /* 상대방이 이 방에서 마지막으로 읽은 메시지 ID */
        (
            SELECT CR.last_read_message_id
            FROM tbl_chat_read CR
            WHERE CR.fk_room_id = CM.fk_room_id
              AND CR.fk_memberid = (
                  SELECT CASE
                           WHEN R.fk_jobseeker_memberid = #{memberId}
                           THEN R.fk_company_memberid
                           ELSE R.fk_jobseeker_memberid
                         END
                  FROM tbl_chat_room R
                  WHERE R.room_id = #{roomId}
              )
        ) AS opponentLastReadMessageId

    FROM tbl_chat_message CM
    WHERE CM.fk_room_id = #{roomId}
      AND CM.deleted_yn = 0


      AND CM.message_id < #{lastMessageId}


    ORDER BY CM.message_id DESC
)
WHERE ROWNUM <= #{size}

